import sys
from collections import deque

def solve():
    input_data = sys.stdin.buffer.read().split()
    idx = 0
    t = int(input_data[idx]); idx += 1
    for _ in range(t):
        n, m = int(input_data[idx]), int(input_data[idx+1]); idx += 2
        grid = []
        lab = None
        for i in range(n):
            row = input_data[idx].decode(); idx += 1
            grid.append(list(row))
            for j, c in enumerate(row):
                if c == 'L':
                    lab = (i, j)

        dirs = [(-1,0),(1,0),(0,-1),(0,1)]
        bad = [[0]*m for _ in range(n)]
        for i in range(n):
            for j in range(m):
                if grid[i][j] != '#':
                    cnt = 0
                    for di,dj in dirs:
                        ni,nj = i+di,j+dj
                        if 0<=ni<n and 0<=nj<m and grid[ni][nj] != '#':
                            cnt += 1
                    bad[i][j] = cnt

        safe = [[False]*m for _ in range(n)]
        q = deque()
        li, lj = lab
        safe[li][lj] = True
        q.append((li,lj))

        while q:
            i,j = q.popleft()
            for di,dj in dirs:
                ni,nj = i+di,j+dj
                if 0<=ni<n and 0<=nj<m and grid[ni][nj] != '#' and not safe[ni][nj]:
                    bad[ni][nj] -= 1
                    if bad[ni][nj] <= 1:
                        safe[ni][nj] = True
                        q.append((ni,nj))

        out = []
        for i in range(n):
            for j in range(m):
                if grid[i][j] == '.' and safe[i][j]:
                    grid[i][j] = '+'
            out.append(''.join(grid[i]))
        print('\n'.join(out))

solve()

